    72→    // Async send message to the remote endpoint. The message may be first
    73→    // put into a pending queue if the channel is busy at that time.
    74→    //
    75→    // Before starting sending data, the hook function "on_sending" will
    76→    // be called to check if the message still need to be sent.
    77→    //
    78→    // If send succeed, callback "on_sent" will be called;
    79→    // else, callback "on_send_failed" will be called. 
    80→    //
    81→    // @param message  the message to send, including header, meta and data.
    82→    // @param cookie  a cookie affiliated to the message, which can carry some
    83→    //                user's customized info. It will not be sent, but would
    84→    //                be passed to the callback function.
    85→    void async_send_message(
    86→            const ReadBufferPtr& message,
    87→            const SendCookie& cookie)
    88→    {
    89→        SOFA_PBRPC_FUNCTION_TRACE;
    90→
    91→        if (is_closed())
    92→        {
    93→            on_send_failed(RPC_ERROR_CONNECTION_CLOSED, message, cookie);
    94→            return;
    95→        }
    96→
    97→        put_into_pending_queue(message, cookie);
    98→
    99→        try_start_send();
   100→    }
